async (params, browser) => {
  // Open ESPN search
  await browser.open(`https://www.espn.com/search/_/q/${params.query}`)

  // Wait for search results
  await browser.waitForSelector('.search-results, .contentItem, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('.contentItem, .search-results li, article').forEach((el, i) => { if (i < 15) { const titleEl = el.querySelector('a h2, .contentItem__title, h3 a'); const descEl = el.querySelector('p, .contentItem__subhead'); const linkEl = titleEl?.closest('a') || el.querySelector('a[href]'); results.push({ title: titleEl?.textContent?.trim() || '', url: linkEl?.href || '', description: descEl?.textContent?.trim()?.slice(0, 200) || '' }); } }); return { query: params.query, result_count: results.length, results: results };`)

  return search_results
}
